        type: "browserPopup",
        width: 1100,
        height: 650,
        title: "DETENTION등록"
    };

    console.log("1.win_url=" + win_url);
    console.log("2.arrParam=" + JSON.stringify(arrParam));
    $c.win.openPopup(win_url, opts, arrParam);
};

//-------------------------------------------------------------------------
// 오더복사
//-------------------------------------------------------------------------
scwin.f_odrCopy = function () {
    var row = ds_ContainerCargoTrackingInformation.getRowPosition();
    var strOrderDetailUrl = "";
    var pgmId = "";

    // 선택된 오더 정보 : 접수번호 / 오더유형/ 운송화물구분코드
    var v_odrNo = ds_ContainerCargoTrackingInformation.getCellData(row, "odrNo");
    var v_odrKndCd = ds_ContainerCargoTrackingInformation.getCellData(row, "odrNo").substring(1, 3);

    let paramObj = {
        PARAM_MAINTAIN_YN: "N",
        odrNo: v_odrNo,
        linkPage: "odrList"
    };    

    if (v_odrKndCd == "C1" || v_odrKndCd == "CS" || v_odrKndCd == "CT") { // 오더 종류가 C1,CS,CT 인 경우
        strOrderDetailUrl = scwin.strCntrOdrRegUrlC1;
        pgmId = strOrderDetailUrl.substring(strOrderDetailUrl.lastIndexOf("/") + 1).replace(/.xml/g,"")+".jsp"

        console.log("1.url=" + strOrderDetailUrl);
        console.log("2.paramObj=" + JSON.stringify(paramObj));
        $c.win.openMenu("수입본선오더", strOrderDetailUrl, pgmId, paramObj, { openAction: "exist" });
    } else if (v_odrKndCd == "C2" || v_odrKndCd == "CX") { // 오더 종류가 C2,CX 인 경우
        strOrderDetailUrl = scwin.strCntrOdrRegUrlC2;
        pgmId = strOrderDetailUrl.substring(strOrderDetailUrl.lastIndexOf("/") + 1).replace(/.xml/g,"")+".jsp"

        console.log("1.url=" + strOrderDetailUrl);
        console.log("2.paramObj=" + JSON.stringify(paramObj));
        $c.win.openMenu("수입일반오더", strOrderDetailUrl, pgmId, paramObj, { openAction: "exist" });
    } else if (v_odrKndCd == "C3" || v_odrKndCd == "CW" || v_odrKndCd == "CR" || v_odrKndCd == "CP") { // 오더 종류가 C3,CW,CR,CP 인 경우
        strOrderDetailUrl = scwin.strCntrOdrRegUrlC3;
        pgmId = strOrderDetailUrl.substring(strOrderDetailUrl.lastIndexOf("/") + 1).replace(/.xml/g,"")+".jsp"

        console.log("1.url=" + strOrderDetailUrl);
        console.log("2.paramObj=" + JSON.stringify(paramObj));
        $c.win.openMenu("수출본선오더", strOrderDetailUrl, pgmId, paramObj, { openAction: "exist" });
    } else if (v_odrKndCd == "C4") { // 오더 종류가 C4 인 경우
        strOrderDetailUrl = scwin.strCntrOdrRegUrlC4;
        pgmId = strOrderDetailUrl.substring(strOrderDetailUrl.lastIndexOf("/") + 1).replace(/.xml/g,"")+".jsp"

        console.log("1.url=" + strOrderDetailUrl);
        console.log("2.paramObj=" + JSON.stringify(paramObj));
        $c.win.openMenu("수출일반오더", strOrderDetailUrl, pgmId, paramObj, { openAction: "exist" });
    } else if (v_odrKndCd == "C5" || v_odrKndCd == "C6" || v_odrKndCd == "C7") { // 오더 종류가 C5,C6,C7 인 경우
        strOrderDetailUrl = scwin.strCntrOdrRegUrlC5;
        pgmId = strOrderDetailUrl.substring(strOrderDetailUrl.lastIndexOf("/") + 1).replace(/.xml/g,"")+".jsp"

        console.log("1.url=" + strOrderDetailUrl);
        console.log("2.paramObj=" + JSON.stringify(paramObj));
        $c.win.openMenu("기타오더", strOrderDetailUrl, pgmId, paramObj, { openAction: "exist" });
    } else if (v_odrKndCd == "B2" || v_odrKndCd == "B4" || v_odrKndCd == "D1" || v_odrKndCd == "D2" || v_odrKndCd == "D3" || v_odrKndCd == "D4" || v_odrKndCd == "D6") { // 오더 종류가 B2,B4,D1,D2,D3,D4,D6 인 경우
        strOrderDetailUrl = scwin.strBulkOdrRegUrl;
        pgmId = strOrderDetailUrl.substring(strOrderDetailUrl.lastIndexOf("/") + 1).replace(/.xml/g,"")+".jsp"

        console.log("1.url=" + strOrderDetailUrl);
        console.log("2.paramObj=" + JSON.stringify(paramObj));
        $c.win.openMenu("벌크오더", strOrderDetailUrl, pgmId, paramObj, { openAction: "exist" });
    } else {
        $c.win.alert("오더종류를 확인하세요.");
    }

}

//-------------------------------------------------------------------------
// B/L 상세  팝업열기
//-------------------------------------------------------------------------
scwin.f_openBlDetailPopup = async function () {
    if (ed_cntrNo.getValue().trim().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["컨테이너번호"]);
        ed_ed_cntrNo.focus();
        return;
    }
    /*
    var xwidth  = "580";
    var yheight = "450";
    var xloc = screen.width/2 - xwidth/2;
    var yloc = screen.height/2 - yheight/2; 
    var win_name  = "BlDetailPop" ;
    var win_style = "left="+xloc+",top="+yloc+",toolbar=no, location=no, directories=no,status=no,menubar=no,scrollbars=no,resizable=no,width="+xwidth+",height="+yheight; 
    */
    let win_url = "/ui/ds/as/cstmrsrvc/coafmgnt/as_102_01_08b.xml";

    let data = {
        cntr_no: ed_cntrNo.getValue()
    };

    let opts = {
        id: "smpPop",
        popupName: "B/L 상세정보",
        modal: false,
        type: "browserPopup",
        width: 700,
        height: 550,
        title: "B/L 상세정보"
    };

    console.log("1.win_url=" + win_url);
    console.log("2.arrParam=" + JSON.stringify(data));
    $c.win.openPopup(win_url, opts, data);
};

scwin.realCmpstcrgYnExp = function (data) {
    return $c.gus.decode(data, 1, "*", "");
}

scwin.sbm_Retrieve1_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    tbx_totalRows2.setValue(ds_ContainerList.getRowCount());

    if (ds_ContainerList.getRowCount() < 1) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        scwin.f_settingContainerInfo("0");
    } else {
        gr_ContainerList.setFocusedCell(0, "vsslCd");

        scwin.f_settingContainerInfo("1");

        tbx_detention.setValue(ds_ContainerInformation.getCellData(ds_ContainerInformation.getRowPosition(), "detention"));

        if (!$c.gus.cfIsNull(ds_ContainerInformation.getCellData(ds_ContainerInformation.getRowPosition(), "cntrRtrnDt"))) {
            tbx_cntrRtrnDt.render.innerHTML = "반납일 : "
                + ds_ContainerInformation.getCellData(ds_ContainerInformation.getRowPosition(), "cntrRtrnDt").substring(0, 4)
                + "/"
                + ds_ContainerInformation.getCellData(ds_ContainerInformation.getRowPosition(), "cntrRtrnDt").substring(4, 6)
                + "/"
                + ds_ContainerInformation.getCellData(ds_ContainerInformation.getRowPosition(), "cntrRtrnDt").substring(6, 8);
        } else {
            tbx_cntrRtrnDt.render.innerHTML = "";
        }

        ds_ContainerList2.set("cntrNo", ds_ContainerList.getCellData(0, "cntrNo"));
        ds_ContainerList2.set("startDt", ds_ContainerList.getCellData(0, "startDt"));

        scwin.f_Tracking_Retrieve();
    }
};

scwin.sbm_Retrieve2_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    tbx_totalRows.setValue(ds_ContainerCargoTrackingInformation.getRowCount());

    if (ds_ContainerInformation.getRowCount() > 0) {
        scwin.f_settingContainerInfo("1");

        tbx_detention.setValue(ds_ContainerInformation.getCellData(0, "detention"));

        if (!$c.gus.cfIsNull(ds_ContainerInformation.getCellData(0, "cntrRtrnDt"))) {
            tbx_cntrRtrnDt.render.innerHTML = "반납일 : "
                + ds_ContainerInformation.getCellData(0, "cntrRtrnDt").substring(0, 4)
                + "/"
                + ds_ContainerInformation.getCellData(0, "cntrRtrnDt").substring(4, 6)
                + "/"
                + ds_ContainerInformation.getCellData(0, "cntrRtrnDt").substring(6, 8)
                + "      반출일 : "
                + ds_ContainerInformation.getCellData(0, "cntrCrryoutCloseDt").substring(0, 4)
                + "/"
                + ds_ContainerInformation.getCellData(0, "cntrCrryoutCloseDt").substring(4, 6)
                + "/"
                + ds_ContainerInformation.getCellData(0, "cntrCrryoutCloseDt").substring(6, 8);
        } else {
            tbx_cntrRtrnDt.render.innerHTML = "";
        }
    }

    if (ds_ContainerCargoTrackingInformation.getRowCount() > 0) {
        //ds_ContainerCargoTrackingInformation.Filter();
        $c.data.dataListFilter(ds_ContainerCargoTrackingInformation, "searcherYn<=0");
    }
};

